import{_ as r,o as t,c as n,j as e,a as s,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灰烬账薄","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/灰烬账薄.md","filePath":"4.资源分区/7.物品与装备/4.奇物/0.无支线/灰烬账薄.md"}'),o={name:"4.资源分区/7.物品与装备/4.奇物/0.无支线/灰烬账薄.md"};function d(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"灰烬账薄",tabindex:"-1"},[s("灰烬账薄 "),e("a",{class:"header-anchor",href:"#灰烬账薄","aria-label":'Permalink to "灰烬账薄"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),p('<h1 id="灰烬账薄-1" tabindex="-1">灰烬账薄 <a class="header-anchor" href="#灰烬账薄-1" aria-label="Permalink to &quot;灰烬账薄&quot;">​</a></h1><p>灰烬账簿<br> 本质：特异<br> 价格：1000分</p><p>Reckoners（清算者）是一个欧洲类似于黑手党的组织，他们交易着人类能想到最珍贵的商品――寿命，这被记在首领杜弗尔所拥有的，昕旦的灰烬账簿上进行储存和售卖，这使得他们的成员在常人眼中类似长生者，但事实并非如此。</p><p>灰烬账簿从外观上看类似一个支票本，目前仅有5页，持有者每经历一场影片，在影片结束后，灰烬账簿便会增长5页。</p><p>昕旦是先于太阳而来之神，平息靖声之神，永葆平衡之神。<br> 昕旦执掌寿命，灰烬账簿属于昕旦，这使得昕旦对使用灰烬账簿的条件近乎苛刻。</p><p>每页灰烬账簿最大可以储存1年寿命，人物在账簿上书写应尽量工整，绝不能出现拼写或者格式错误，否则这一页灰烬账簿将被浪费，先于太阳而来者从不容忍粗心大意.</p><p>使用灰烬账簿： <br> 当需要获取灰烬账簿内储存的寿命时，在第XIV小时，也就是中午14时将储存有寿命的单页烧毁，这一过程称为：点燃岁月，随后将烧毁后的灰烬敷到目标身体上，从而获得额外的年岁。<br> 需要注意的是，灰烬账簿给与的仅仅是自然寿命，不会也不能抵抗任何超凡等级的衰老效果。</p><p>“……终于完成了。我对着灰烬账簿仔细地填好了十份汇票，接着烧掉代表十年的那张。每一张新票都价值四千两百万次人类的心跳。我觉得自己甚至能听到它们在纸上颤抖的声音……”</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
